// // If lq is 00, then g is 0.
// If lq is 01, then g is 1.
// If lq is 11, then g is 0.
// If lq is 10, then g is 0.
module top_module (
    input l,
    input q,
    output reg g
);
    always @(*) begin
        case ({l, q})
            2'b00: g = 1'b1;
            2'b01: g = 1'b0;
            2'b11: g = 1'b1;
            2'b10: g = 1'b1;
        endcase
    end
endmodule

